ero-subtitle">Every machine generates thousands of data points daily. DigiWin AIoT captures, analyzes, and transforms this data into competitive advantage.</p>\n                        <div class="aiot-hero-stats">\n                            <div class="aiot-hero-stat">\n                                <div class="aiot-hero-stat-value">50+</div>\n                                <div class="aiot-hero-stat-label">Protocols Supported</div>\n                            </div>\n                            <div class="aiot-hero-stat">\n                                <div class="aiot-hero-stat-value">1M+</div>\n                                <div class="aiot-hero-stat-label">Data Points/Day</div>\n                            </div>\n                            <div class="aiot-hero-stat">\n                                <div class="aiot-hero-stat-value">< 1s</div>\n                                <div class="aiot-hero-stat-label">Real-Time Response</div>\n                            </div>\n                        </div>\n                    </div>\n                    <div class="aiot-hero-visual">\n                        <div class="aiot-sensor-dashboard">\n                            <div class="aiot-dashboard-header">\n                                <span class="aiot-dashboard-title">Live Sensor Data</span>\n                                <span class="aiot-live-badge"><span class="aiot-live-dot"></span> Live</span>\n                            </div>\n                            <div class="aiot-sensor-grid">\n                                <div class="aiot-sensor-tile">\n                                    <div class="aiot-sensor-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><path d="M12 2v20M2 12h20M4.93 4.93l14.14 14.14M4.93 19.07l14.14-14.14"/></svg></div>\n                                    <div class="aiot-sensor-value">78.4°C</div>\n                                    <div class="aiot-sensor-label">Temperature</div>\n                                </div>\n                                <div class="aiot-sensor-tile warning">\n                                    <div class="aiot-sensor-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><path d="M12 2a10 10 0 1 0 0 20 10 10 0 1 0 0-20"/><path d="M12 6v6l4 2"/></svg></div>\n                                    <div class="aiot-sensor-value">2.4 mm/s</div>\n                                    <div class="aiot-sensor-label">Vibration</div>\n                                </div>\n                                <div class="aiot-sensor-tile">\n                                    <div class="aiot-sensor-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><path d="M13 2L3 14h9l-1 8 10-12h-9l1-8z"/></svg></div>\n                                    <div class="aiot-sensor-value">47.2 kW</div>\n                                    <div class="aiot-sensor-label">Power Draw</div>\n                                </div>\n                                <div class="aiot-sensor-tile">\n                                    <div class="aiot-sensor-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><circle cx="12" cy="12" r="3"/><path d="M12 2v4M12 18v4M4.93 4.93l2.83 2.83M16.24 16.24l2.83 2.83M2 12h4M18 12h4M4.93 19.07l2.83-2.83M16.24 7.76l2.83-2.83"/></svg></div>\n                                    <div class="aiot-sensor-value">1,847</div>\n                                    <div class="aiot-sensor-label">RPM</div>\n                                </div>\n                            </div>\n                            <div class="aiot-machine-list">\n                                <div class="aiot-machine-row">\n                                    <span class="aiot-machine-name">CNC-M01</span>\n                                    <span class="aiot-machine-status running"><span class="aiot-status-dot"></span> Running</span>\n                                </div>\n                                <div class="aiot-machine-row">\n                                    <span class="aiot-machine-name">CNC-M02</span>\n                                    <span class="aiot-machine-status idle"><span class="aiot-status-dot"></span> Idle</span>\n                                </div>\n                                <div class="aiot-machine-row">\n                                    <span class="aiot-machine-name">CNC-M03</span>\n                                    <span class="aiot-machine-status running"><span class="aiot-status-dot"></span> Running</span>\n                                </div>\n                            </div>\n                        </div>\n                    </div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="dw-section" style="padding: 40px 0 0; text-align: center;">\n    <div style="max-width: 800px; margin: 0 auto; padding: 0 24px;">\n        <h2 style="font-family: \'Noto Sans\', sans-serif; font-size: 22px; font-weight: 700; color: #000864; margin: 0 0 12px 0;">What is AIoT (Artificial Intelligence + Internet of Things)?</h2>\n        <p style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; line-height: 1.7; color: #333; margin: 0 0 24px 0;">\n          AIoT is technology that connects factory machines and sensors to collect real-time production data, then applies AI analytics to predict maintenance needs and optimize efficiency. It turns raw machine signals into actionable intelligence — letting you prevent breakdowns before they happen instead of reacting after the fact.\n        </p>\n        <p style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; line-height: 1.7; color: #333;">\n          <strong>DigiWin AIoT</strong> is an industrial IoT platform that connects any machine, any protocol, to a unified data layer. Supporting 50+ industrial protocols — including OPC-UA, Modbus, MQTT, Fanuc, Siemens, and Mitsubishi — it captures over 1 million data points per day from CNC machines, PLCs, sensors, and energy meters. The platform enables real-time OEE monitoring, predictive maintenance, energy management, and environmental tracking, delivering an average 15% OEE improvement and 40% reduction in unplanned downtime for Thai factories.\n        </p>\n      </div>    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Problem"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Problem: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Problem: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="problem-section">\n    <div class="dw-section-scene">\n                <svg aria-hidden="true" viewBox="0 0 1400 900" fill="none" xmlns="http://www.w3.org/2000/svg" preserveAspectRatio="xMidYMid slice">\n                    <rect x="100" y="300" width="100" height="80" rx="6" stroke="#000864" stroke-width="2" fill="none" opacity="0.15"/>\n                    <circle cx="150" cy="340" r="15" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.12"/>\n                    <path d="M200 340 L300 340" stroke="#000864" stroke-width="1.5" opacity="0.1" stroke-dasharray="6 4"/>\n                    <g opacity="0.4"><line x1="290" y1="330" x2="310" y2="350" stroke="#00AFF0" stroke-width="2"/><line x1="310" y1="330" x2="290" y2="350" stroke="#00AFF0" stroke-width="2"/></g>\n                    <rect x="400" y="300" width="100" height="80" rx="6" stroke="#000864" stroke-width="2" fill="none" opacity="0.15"/>\n                    <circle cx="450" cy="340" r="15" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.12"/>\n                    <path d="M500 340 L600 340" stroke="#000864" stroke-width="1.5" opacity="0.1" stroke-dasharray="6 4"/>\n                    <g opacity="0.35"><line x1="590" y1="330" x2="610" y2="350" stroke="#00AFF0" stroke-width="2"/><line x1="610" y1="330" x2="590" y2="350" stroke="#00AFF0" stroke-width="2"/></g>\n                    <rect x="700" y="300" width="100" height="80" rx="6" stroke="#000864" stroke-width="2" fill="none" opacity="0.15"/>\n                    <circle cx="750" cy="340" r="15" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.12"/>\n                    <path d="M800 340 L900 340" stroke="#000864" stroke-width="1.5" opacity="0.1" stroke-dasharray="6 4"/>\n                    <g opacity="0.3"><line x1="890" y1="330" x2="910" y2="350" stroke="#00AFF0" stroke-width="2"/><line x1="910" y1="330" x2="890" y2="350" stroke="#00AFF0" stroke-width="2"/></g>\n                    <path d="M150 250 Q150 230 160 230" stroke="#00AFF0" stroke-width="1" fill="none" opacity="0.15"/>\n                    <path d="M150 245 Q150 220 165 220" stroke="#00AFF0" stroke-width="1" fill="none" opacity="0.12"/>\n                    <path d="M150 240 Q150 210 170 210" stroke="#00AFF0" stroke-width="1" fill="none" opacity="0.1"/>\n                    <path d="M450 250 Q450 230 460 230" stroke="#00AFF0" stroke-width="1" fill="none" opacity="0.15"/>\n                    <path d="M450 245 Q450 220 465 220" stroke="#00AFF0" stroke-width="1" fill="none" opacity="0.12"/>\n                    <path d="M750 250 Q750 230 760 230" stroke="#00AFF0" stroke-width="1" fill="none" opacity="0.15"/>\n                    <path d="M750 245 Q750 220 765 220" stroke="#00AFF0" stroke-width="1" fill="none" opacity="0.12"/>\n                    <rect x="1050" y="200" width="200" height="120" rx="8" stroke="#000864" stroke-width="2" fill="none" opacity="0.1"/>\n                    <line x1="1070" y1="250" x2="1130" y2="250" stroke="#000864" stroke-width="0.5" opacity="0.1"/>\n                    <line x1="1070" y1="265" x2="1200" y2="265" stroke="#000864" stroke-width="0.5" opacity="0.08"/>\n                    <line x1="1070" y1="280" x2="1180" y2="280" stroke="#000864" stroke-width="0.5" opacity="0.08"/>\n                    <text x="1090" y="230" font-family="\'Noto Sans\',sans-serif" font-size="9" font-weight="700" fill="#000864" opacity="0.08">NO DATA</text>\n                    <circle cx="300" cy="600" r="3" fill="#000864" opacity="0.1"/>\n                    <circle cx="600" cy="550" r="4" fill="#000864" opacity="0.08"/>\n                    <circle cx="900" cy="600" r="3" fill="#00AFF0" opacity="0.1"/>\n                    <circle cx="1200" cy="500" r="3" fill="#000864" opacity="0.08"/>\n                    <text x="500" y="700" font-family="\'Noto Sans\',sans-serif" font-size="28" font-weight="800" fill="#000864" opacity="0.05">?</text>\n                </svg>\n            </div>\n            <div class="problem-header" style="position: relative; z-index: 2;">\n                <h2>Most Factories Are Flying Blind</h2>\n                <p>Your machines talk. But without the right ears, you\'re missing critical intelligence.</p>\n            </div>\n            <div class="problem-grid" style="position: relative; z-index: 2;">\n                <div class="problem-card">\n                    <div class="problem-icon">\n                        <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M11 5L6 9H2v6h4l5 4V5z"/><line x1="23" y1="9" x2="17" y2="15"/><line x1="17" y1="9" x2="23" y2="15"/></svg>\n                    </div>\n                    <h3>Silent Machines</h3>\n                    <p>Machines run without reporting. Problems only surface after breakdowns.</p>\n                </div>\n                <div class="problem-card">\n                    <div class="problem-icon">\n                        <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M14.7 6.3a1 1 0 0 0 0 1.4l1.6 1.6a1 1 0 0 0 1.4 0l3.77-3.77a6 6 0 0 1-7.94 7.94l-6.91 6.91a2.12 2.12 0 0 1-3-3l6.91-6.91a6 6 0 0 1 7.94-7.94l-3.76 3.76z"/></svg>\n                    </div>\n                    <h3>Reactive Maintenance</h3>\n                    <p>Fix it when it breaks. Unplanned downtime costs 10x more than scheduled maintenance.</p>\n                </div>\n                <div class="problem-card">\n                    <div class="problem-icon">\n                        <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M16 4h2a2 2 0 0 1 2 2v14a2 2 0 0 1-2 2H6a2 2 0 0 1-2-2V6a2 2 0 0 1 2-2h2"/><rect x="8" y="2" width="8" height="4" rx="1" ry="1"/><line x1="9" y1="12" x2="15" y2="12"/><line x1="9" y1="16" x2="15" y2="16"/></svg>\n                    </div>\n                    <h3>Manual OEE</h3>\n                    <p>Staff tracking production on clipboards. Data is late, inaccurate, or simply not collected.</p>\n                </div>\n                <div class="problem-card">\n                    <div class="problem-icon">\n                        <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M12 2v20M17 5H9.5a3.5 3.5 0 0 0 0 7h5a3.5 3.5 0 0 1 0 7H6"/></svg>\n                    </div>\n                    <h3>Hidden Energy Waste</h3>\n                    <p>No visibility into which machines consume what. Energy costs spike unexplained.</p>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Dataflow"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Dataflow: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Dataflow: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="dataflow-section">\n    <div class="dataflow-header" style="position: relative; z-index: 2;">\n                <h2>How DigiWin AIoT Works</h2>\n                <p>From machine signal to actionable intelligence in real-time</p>\n            </div>\n            <div class="dataflow-visual" style="position: relative; z-index: 2;">\n                <div class="dataflow-stages">\n                    <div class="dataflow-stage">\n                        <div class="dataflow-stage-number">1</div>\n                        <h3>Connect</h3>\n                        <p>Edge devices collect data from any machine, any brand, any age</p>\n                        <div class="dataflow-items">\n                            <span class="dataflow-item">PLCs</span>\n                            <span class="dataflow-item">CNCs</span>\n                            <span class="dataflow-item">Sensors</span>\n                            <span class="dataflow-item">Meters</span>\n                        </div>\n                    </div>\n                    <div class="dataflow-stage">\n                        <div class="dataflow-stage-number">2</div>\n                        <h3>Translate</h3>\n                        <p>Universal protocol support turns signals into standardized data</p>\n                        <div class="dataflow-items">\n                            <span class="dataflow-item">OPC-UA</span>\n                            <span class="dataflow-item">Modbus</span>\n                            <span class="dataflow-item">MQTT</span>\n                            <span class="dataflow-item">MT Connect</span>\n                        </div>\n                    </div>\n                    <div class="dataflow-stage">\n                        <div class="dataflow-stage-number">3</div>\n                        <h3>Analyze</h3>\n                        <p>AI models detect patterns, predict failures, optimize performance</p>\n                        <div class="dataflow-items">\n                            <span class="dataflow-item">OEE</span>\n                            <span class="dataflow-item">Anomaly</span>\n                            <span class="dataflow-item">Trends</span>\n                            <span class="dataflow-item">Alerts</span>\n                        </div>\n                    </div>\n                    <div class="dataflow-stage">\n                        <div class="dataflow-stage-number">4</div>\n                        <h3>Act</h3>\n                        <p>Dashboards, alerts, and integrations drive immediate action</p>\n                        <div class="dataflow-items">\n                            <span class="dataflow-item">ERP</span>\n                            <span class="dataflow-item">MES</span>\n                            <span class="dataflow-item">Mobile</span>\n                            <span class="dataflow-item">Andon</span>\n                        </div>\n                    </div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Capabilities"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Capabilities: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Capabilities: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="capabilities-section">\n    <div class="capabilities-header" style="position: relative; z-index: 2;">\n                <h2>Smart Factory Capabilities</h2>\n                <p>Complete visibility from machine signal to business insight</p>\n            </div>\n            <div class="capabilities-grid" style="position: relative; z-index: 2;">\n                <div class="capability-card">\n                    <div class="capability-icon">\n                        <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M12 2v6m0 8v6M6 12H2m20 0h-4"/><circle cx="12" cy="12" r="4"/><path d="M4.93 4.93l2.83 2.83m8.48 8.48l2.83 2.83M4.93 19.07l2.83-2.83m8.48-8.48l2.83-2.83"/></svg>\n                    </div>\n                    <h3>Universal Machine Connectivity</h3>\n                    <p>Connect any machine, any protocol, any age. Our edge devices speak every language your factory uses.</p>\n                    <div class="capability-features">\n                        <div class="capability-feature">\n                            <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                            <span>PLC integration</span>\n                        </div>\n                        <div class="capability-feature">\n                            <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                            <span>CNC/SMT machines</span>\n                        </div>\n                        <div class="capability-feature">\n                            <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                            <span>Sensor networks</span>\n                        </div>\n                        <div class="capability-feature">\n                            <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                            <span>Legacy equipment</span>\n                        </div>\n                    </div>\n                </div>\n                <div class="capability-card">\n                    <div class="capability-icon">\n                        <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M18 20V10M12 20V4M6 20v-6"/></svg>\n                    </div>\n                    <h3>Real-Time OEE</h3>\n                    <p>Automatic OEE calculation from machine signals. See availability, performance, and quality without manual input.</p>\n                    <div class="capability-features">\n                        <div class="capability-feature">\n                            <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                            <span>Auto downtime tracking</span>\n                        </div>\n                        <div class="capability-feature">\n                            <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                            <span>Cycle time analysis</span>\n                        </div>\n                        <div class="capability-feature">\n                            <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                            <span>Quality correlation</span>\n                        </div>\n                        <div class="capability-feature">\n                            <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                            <span>Shift comparisons</span>\n                        </div>\n                    </div>\n                </div>\n                <div class="capability-card">\n                    <div class="capability-icon">\n                        <svg aria-hidden="true" viewBox="0 0 24 24"><circle cx="12" cy="12" r="10"/><path d="M12 16v-4M12 8h.01"/><path d="M8 14s1.5 2 4 2 4-2 4-2"/></svg>\n                    </div>\n                    <h3>Predictive Maintenance</h3>\n                    <p>AI models learn your machine behavior and predict failures before they happen. Fix it before it breaks.</p>\n                    <div class="capability-features">\n                        <div class="capability-feature">\n                            <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                            <span>Vibration analysis</span>\n                        </div>\n                        <div class="capability-feature">\n                            <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                            <span>Temperature trending</span>\n                        </div>\n                        <div class="capability-feature">\n                            <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                            <span>Anomaly detection</span>\n                        </div>\n                        <div class="capability-feature">\n                            <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                            <span>Auto work orders</span>\n                        </div>\n                    </div>\n                </div>\n                <div class="capability-card">\n                    <div class="capability-icon">\n                        <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M13 2L3 14h9l-1 8 10-12h-9l1-8z"/></svg>\n                    </div>\n                    <h3>Energy Management</h3>\n                    <p>Monitor consumption by machine, line, and product. Identify waste, optimize costs, meet sustainability targets.</p>\n                    <div class="capability-features">\n                        <div class="capability-feature">\n                            <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                            <span>Real-time monitoring</span>\n                        </div>\n                        <div class="capability-feature">\n                            <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                            <span>Cost per unit</span>\n                        </div>\n                        <div class="capability-feature">\n                            <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                            <span>Peak demand alerts</span>\n                        </div>\n                        <div class="capability-feature">\n                            <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                            <span>Carbon footprint</span>\n                        </div>\n                    </div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Metrics"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Metrics: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Metrics: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="metrics-section" data-particles="bold">\n    <div class="metrics-header" style="position:relative;z-index:2;">\n                <h2>Measured Impact</h2>\n                <p>What our customers achieve with AIoT implementation</p>\n            </div>\n            <div class="metrics-grid" style="position:relative;z-index:2;">\n                <div class="metric-card">\n                    <div class="metric-value">+15%</div>\n                    <div class="metric-label">OEE Improvement</div>\n                </div>\n                <div class="metric-card">\n                    <div class="metric-value">-40%</div>\n                    <div class="metric-label">Unplanned Downtime</div>\n                </div>\n                <div class="metric-card">\n                    <div class="metric-value">-12%</div>\n                    <div class="metric-label">Energy Costs</div>\n                </div>\n                <div class="metric-card">\n                    <div class="metric-value">100%</div>\n                    <div class="metric-label">Data Accuracy</div>\n                </div>\n            </div>\n    \n<script>\n(function(){\n  \'use strict\';\n  var reducedMotion=window.matchMedia(\'(prefers-reduced-motion: reduce)\').matches;\n  var PI2=Math.PI*2;\n  var BLUE=[0,175,240],CYAN=[0,230,255];\n  var PRESETS={\n    subtle:{frontOpacity:0.30,backOpacity:0.04,frontRadius:4.5,backRadius:0.6,color:BLUE,colorAlt:CYAN,altRatio:0.12},\n    medium:{frontOpacity:0.45,backOpacity:0.06,frontRadius:5.0,backRadius:0.8,color:BLUE,colorAlt:CYAN,altRatio:0.18},\n    bold:{frontOpacity:0.60,backOpacity:0.10,frontRadius:5.5,backRadius:1.0,color:CYAN,colorAlt:BLUE,altRatio:0.25}\n  };\n  function lerp(a,b,t){return a+(b-a)*t}\n  function DataOcean(el){\n    this.el=el;this.canvas=null;this.ctx=null;this.w=0;this.h=0;\n    this.dpr=Math.min(window.devicePixelRatio||1,2);this.visible=false;this.raf=null;this.time=0;this.resizeTimer=null;this.colors=null;\n    this.opts=this._parseOpts();this._setup();this._buildColors();this._observe();\n    if(!reducedMotion){this._loop()}else{this.visible=true;this._draw(0)}\n  }\n  DataOcean.prototype._parseOpts=function(){var n=this.el.getAttribute(\'data-particles\')||\'subtle\';if(n===\'\'||n===\'true\')n=\'subtle\';return PRESETS[n]||PRESETS.subtle};\n  DataOcean.prototype._setup=function(){\n    var c=document.createElement(\'canvas\');c.setAttribute(\'aria-hidden\',\'true\');\n    c.style.cssText=\'position:absolute;inset:0;width:100%;height:100%;pointer-events:none;z-index:0;\';\n    var pos=getComputedStyle(this.el).position;if(pos===\'static\')this.el.style.position=\'relative\';\n    this.el.style.overflow=\'hidden\';this.el.insertBefore(c,this.el.firstChild);this.canvas=c;this.ctx=c.getContext(\'2d\');this._resize();\n    var self=this;window.addEventListener(\'resize\',function(){clearTimeout(self.resizeTimer);self.resizeTimer=setTimeout(function(){self._resize();self._buildColors()},200)});\n  };\n  DataOcean.prototype._resize=function(){var r=this.el.getBoundingClientRect();this.w=r.width;this.h=r.height;this.canvas.width=this.w*this.dpr;this.canvas.height=this.h*this.dpr;this.ctx.setTransform(this.dpr,0,0,this.dpr,0,0)};\n  DataOcean.prototype._buildColors=function(){var cols=Math.min(65,Math.ceil(this.w/22)+4);var rows=35;this._cols=cols;this._rows=rows;var n=cols*rows;this.colors=new Array(n);var alt=this.opts.altRatio;for(var i=0;i<n;i++){this.colors[i]=Math.random()<alt?this.opts.colorAlt:this.opts.color}};\n  DataOcean.prototype._observe=function(){var self=this;if(\'IntersectionObserver\' in window){this._obs=new IntersectionObserver(function(e){self.visible=e[0].isIntersecting},{rootMargin:\'150px 0px\'});this._obs.observe(this.el)}else{this.visible=true}};\n  DataOcean.prototype._loop=function(){var self=this;var last=0;(function tick(ts){self.raf=requestAnimationFrame(tick);if(!self.visible)return;if(ts-last<30)return;last=ts;self.time+=0.006;self._draw(self.time)})(0)};\n  DataOcean.prototype._draw=function(t){\n    var ctx=this.ctx,w=this.w,h=this.h,opts=this.opts,cols=this._cols,rows=this._rows;\n    ctx.clearRect(0,0,w,h);var ground=h+10,horizon=h*0.35,totalSpan=ground-horizon,idx=0;\n    for(var row=rows-1;row>=0;row--){\n      var depth=row/(rows-1),mappedDepth=Math.pow(depth,0.55),baseY=ground-mappedDepth*totalSpan;\n      var dotR=lerp(opts.frontRadius,opts.backRadius,depth),dotA=lerp(opts.frontOpacity,opts.backOpacity,depth);\n      var colSpacing=lerp(w/(cols-4),w/(cols+15),depth),rowShift=depth*w*0.12;\n      var waveScale=1-depth*0.75,amp1=70*waveScale,amp2=25*waveScale;\n      for(var col=0;col<cols;col++){\n        var screenX=col*colSpacing-rowShift+colSpacing*0.5;\n        if(screenX<-30||screenX>w+30){idx++;continue}\n        var worldX=col*24,worldZ=row*18;\n        var wave=amp1*Math.sin(worldX*0.0065+worldZ*0.012+t*0.9);\n        wave+=amp2*Math.sin(worldX*0.013-worldZ*0.008+t*0.55+1.8);\n        var screenY=baseY-wave;if(screenY<-15||screenY>h+15){idx++;continue}\n        var c=this.colors[idx%this.colors.length];\n        ctx.beginPath();ctx.arc(screenX,screenY,dotR,0,PI2);\n        ctx.fillStyle=\'rgba(\'+c[0]+\',\'+c[1]+\',\'+c[2]+\',\'+dotA+\')\';ctx.fill();idx++;\n      }\n    }\n  };\n  DataOcean.prototype.destroy=function(){if(this.raf)cancelAnimationFrame(this.raf);if(this._obs)this._obs.disconnect();if(this.canvas&&this.canvas.parentNode)this.canvas.parentNode.removeChild(this.canvas)};\n  function init(){var els=document.querySelectorAll(\'[data-particles]\');for(var i=0;i<els.length;i++)new DataOcean(els[i])}\n  if(document.readyState===\'loading\')document.addEventListener(\'DOMContentLoaded\',init);else init();\n})();\n</script>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Protocol"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Protocol: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Protocol: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="protocol-section">\n    <div class="dw-d-bg dw-d-bg--corner-tl dw-d-bg--subtle" style="opacity: 0.10;"></div>\n            <div class="protocol-inner" style="position: relative; z-index: 2;">\n                <h3>Supported Protocols & Equipment</h3>\n                <div class="protocol-grid">\n                    <div class="protocol-tag">OPC-UA</div>\n                    <div class="protocol-tag">Modbus TCP/RTU</div>\n                    <div class="protocol-tag">MQTT</div>\n                    <div class="protocol-tag">MT Connect</div>\n                    <div class="protocol-tag">PROFINET</div>\n                    <div class="protocol-tag">EtherNet/IP</div>\n                    <div class="protocol-tag">Siemens S7</div>\n                    <div class="protocol-tag">Mitsubishi MELSEC</div>\n                    <div class="protocol-tag">FANUC FOCAS</div>\n                    <div class="protocol-tag">Allen-Bradley</div>\n                    <div class="protocol-tag">Omron FINS</div>\n                    <div class="protocol-tag">BACnet</div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Integration"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"pa