x="0 0 24 24"><rect x="2" y="7" width="20" height="14" rx="2"/><path d="M6 7V5a2 2 0 0 1 2-2h8a2 2 0 0 1 2 2v2"/><line x1="6" y1="12" x2="6" y2="12"/><line x1="10" y1="12" x2="10" y2="12"/><line x1="14" y1="12" x2="14" y2="12"/><line x1="18" y1="12" x2="18" y2="12"/></svg>\n                    </div>\n                    <div class="node-title">MES</div>\n                    <div class="node-subtitle">MES / SFT</div>\n                </a>\n                <span class="integration-arrow">↔</span>\n                <div class="integration-node aiot-active">\n                    <div class="node-icon">\n                        <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M12 2v4m0 12v4M4.93 4.93l2.83 2.83m8.48 8.48l2.83 2.83M2 12h4m12 0h4M4.93 19.07l2.83-2.83m8.48-8.48l2.83-2.83"/><circle cx="12" cy="12" r="3"/></svg>\n                    </div>\n                    <div class="node-title">AIoT</div>\n                    <div class="node-subtitle">Machine Layer</div>\n                </div>\n                <span class="integration-arrow">↔</span>\n                <a href="/products/wms/" class="integration-node">\n                    <div class="node-icon">\n                        <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M21 16V8a2 2 0 0 0-1-1.73l-7-4a2 2 0 0 0-2 0l-7 4A2 2 0 0 0 3 8v8a2 2 0 0 0 1 1.73l7 4a2 2 0 0 0 2 0l7-4A2 2 0 0 0 21 16z"/><polyline points="3.29 7 12 12 20.71 7"/><line x1="12" y1="22" x2="12" y2="12"/></svg>\n                    </div>\n                    <div class="node-title">WMS</div>\n                    <div class="node-subtitle">sFLS</div>\n                </a>\n            </div>\n    \n            <div class="integration-message">\n                <div class="integration-gradient-bar" aria-hidden="true"></div>\n                <p>Machine data flows from sensors to dashboards in real time. AIoT feeds OEE to MES, triggers maintenance in ERP, and validates inventory in WMS. <strong>One connected factory. Zero blind spots.</strong></p>\n            </div>\n    \n            <div class="integration-links">\n                <a href="/products/erp/" class="integration-link">Explore ERP <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M5 12h14M12 5l7 7-7 7"/></svg></a>\n                <a href="/products/mes/" class="integration-link">Explore MES <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M5 12h14M12 5l7 7-7 7"/></svg></a>\n                <a href="/products/wms/" class="integration-link">Explore WMS <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M5 12h14M12 5l7 7-7 7"/></svg></a>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section 2"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section 2: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section 2: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="aiot-faq">\n    <div style="max-width: 800px; margin: 0 auto; padding: 0 24px;">\n            <h2 style="font-family: \'Noto Sans\', sans-serif; font-size: 28px; font-weight: 700; color: #000864; margin-bottom: 32px; text-align: center;">Frequently Asked Questions</h2>\n            <div style="display: flex; flex-direction: column; gap: 12px;">\n              <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n                <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">What is Industrial AIoT?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n                <div style="padding: 0 20px 16px 20px; background: white;">\n                  <p style="font-family: \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.7; color: #333; margin: 0;">Industrial AIoT (Artificial Intelligence of Things) combines IoT sensor connectivity with AI-driven analytics for manufacturing. It connects factory machines, PLCs, and sensors to a unified data platform that monitors equipment health, calculates OEE automatically, predicts failures before they happen, and optimizes energy consumption — turning raw machine data into actionable intelligence.</p>\n                </div>\n              </details>\n              <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n                <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">What machines and protocols does DigiWin AIoT support?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n                <div style="padding: 0 20px 16px 20px; background: white;">\n                  <p style="font-family: \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.7; color: #333; margin: 0;">DigiWin AIoT supports 50+ industrial protocols including OPC-UA, Modbus TCP/RTU, MQTT, MT Connect, PROFINET, EtherNet/IP, Siemens S7, Mitsubishi MELSEC, FANUC FOCAS, Allen-Bradley, Omron FINS, and BACnet. It connects to CNC machines, injection molding machines, PLCs, robots, energy meters, and environmental sensors from any brand and any age.</p>\n                </div>\n              </details>\n              <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n                <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">Do I need to replace my existing machines to use AIoT?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n                <div style="padding: 0 20px 16px 20px; background: white;">\n                  <p style="font-family: \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.7; color: #333; margin: 0;">No. DigiWin AIoT retrofits onto existing equipment regardless of age or brand. Edge devices connect to machine control interfaces (PLCs, CNCs) or add external sensors (vibration, temperature, power) to machines without digital outputs. Even 20-year-old equipment can be connected without any modification to the machine itself.</p>\n                </div>\n              </details>\n              <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n                <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">How does AIoT connect to ERP and MES?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n                <div style="padding: 0 20px 16px 20px; background: white;">\n                  <p style="font-family: \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.7; color: #333; margin: 0;">DigiWin AIoT is built on the same platform as DigiWin ERP and MES, sharing one database. Machine data flows automatically from sensors through AIoT into MES for OEE calculations and into ERP for maintenance work orders and production costing. No middleware, no manual data entry, no integration projects required.</p>\n                </div>\n              </details>\n              <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n                <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">What ROI can I expect from factory AIoT?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n                <div style="padding: 0 20px 16px 20px; background: white;">\n                  <p style="font-family: \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.7; color: #333; margin: 0;">DigiWin AIoT customers typically achieve a 15% OEE improvement, 40% reduction in unplanned downtime, and 12% energy cost savings. Most factories see payback within 6–12 months. The immediate wins come from eliminating manual data collection and making machine status visible in real time.</p>\n                </div>\n              </details>\n            </div>\n          </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA: Start Listening to Your Machines"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA: Start Listening to Your Machines: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA: Start Listening to Your Machines: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="aiot-cta-section">\n    <div class="aiot-cta-super-d" aria-hidden="true"></div>\n    <div class="aiot-cta-wave-flow" aria-hidden="true"></div>\n    <div class="aiot-cta-container">\n      <h2 class="aiot-cta-title">Start Listening to Your Machines</h2>\n      <p class="aiot-cta-subtitle">See what your factory floor is really doing</p>\n      <div class="aiot-cta-btn-row">\n        <a href="/demo/" class="aiot-cta-btn aiot-cta-btn--primary">Get in Touch</a>\n        <a href="/products/" class="aiot-cta-btn aiot-cta-btn--ghost">Explore All Products</a>\n      </div>\n    </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Column"}}},"decoration":{}}} -->\n<!-- wp:html --><style>\n.aiot-related-grid{display:grid!important;grid-template-columns:repeat(auto-fit,minmax(280px,1fr))!important;gap:24px!important;max-width:1200px!important;margin:0 auto!important}\n.aiot-related-card{display:block!important;padding:24px!important;background:#fff!important;border-radius:12px!important;text-decoration:none!important;border:1px solid #e5e7eb!important;color:#333!important;line-height:1.6!important}\n.aiot-related-card-title{font-size:18px!important;font-weight:600!important;color:#000864!important;margin:0 0 8px 0!important}\n.aiot-related-card-desc{font-size:14px!important;color:#666!important;margin:0!important}\n</style><div class="aiot-related-section">\n    <h2 class="aiot-related-heading">Explore Related Solutions</h2>\n    <div class="aiot-related-grid">\n      <a href="/products/erp/" class="aiot-related-card">\n        <h3 class="aiot-related-card-title">ERP</h3>\n        <p class="aiot-related-card-desc">End-to-end manufacturing ERP built for Thai factories — from BOM to financials to BOI compliance.</p>\n      </a>\n      <a href="/products/mes/" class="aiot-related-card">\n        <h3 class="aiot-related-card-title">MES</h3>\n        <p class="aiot-related-card-desc">Real-time shop floor execution system — OEE tracking, SPC, and paperless work orders.</p>\n      </a>\n      <a href="/products/wms/" class="aiot-related-card">\n        <h3 class="aiot-related-card-title">WMS</h3>\n        <p class="aiot-related-card-desc">Smart warehouse management with barcode/RFID — from receiving to dispatch with full traceability.</p>\n      </a>\n      <a href="/industries/automotive/" class="aiot-related-card">\n        <h3 class="aiot-related-card-title">Automotive</h3>\n        <p class="aiot-related-card-desc">ERP and MES solutions purpose-built for automotive parts manufacturers and OEM suppliers.</p>\n      </a>\n      <a href="/industries/electronics/" class="aiot-related-card">\n        <h3 class="aiot-related-card-title">Electronics</h3>\n        <p class="aiot-related-card-desc">Manufacturing software for electronics assembly, SMT lines, and component traceability.</p>\n      </a>\n      <a href="/industries/metal-plastics/" class="aiot-related-card">\n        <h3 class="aiot-related-card-title">Metal &amp; Plastics</h3>\n        <p class="aiot-related-card-desc">Integrated solutions for die casting, injection molding, and metal fabrication shops.</p>\n      </a>\n    </div>\n  </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- /wp:divi/placeholder -->',
  post_modified = NOW(),
  post_modified_gmt = UTC_TIMESTAMP()
WHERE ID = 100564;

-- Step 2: Update Divi 5 custom CSS
DELETE FROM wp_postmeta WHERE post_id = 100564 AND meta_key = '_et_pb_custom_css';
INSERT INTO wp_postmeta (post_id, meta_key, meta_value) VALUES (100564, '_et_pb_custom_css', '/* === GLOBAL DIVI THEME RESET === */\n.et_pb_section,.et_pb_row,.et_pb_column,.et_pb_code,.et_pb_code_inner{font-family:\'Noto Sans\',sans-serif !important;font-weight:400 !important;font-size:16px !important;color:#333 !important}\n.et_pb_section h1,.et_pb_section h2,.et_pb_section h3,.et_pb_section h4,.et_pb_section h5,.et_pb_section h6{padding-bottom:0 !important}\n.et_pb_section:not([class*=\'tb_body\']){overflow:hidden !important;margin:0 !important}\n.et_pb_row:not([class*=\'tb_body\']){max-width:100% !important;width:100% !important;padding:0 !important;margin-top:0 !important;margin-bottom:0 !important;gap:0 !important}\n.et_pb_column:not([class*=\'tb_body\']){padding:0 !important;margin:0 !important;gap:0 !important}\n.et_pb_section .et_pb_row .et_pb_column .et_pb_text.et_pb_module{margin:0 !important;padding:0 !important}\n.section-title{line-height:1.6;-webkit-font-smoothing:auto}\n.section-subtitle{margin-left:auto;margin-right:auto;line-height:1.6}\n/* fade-in / scroll-fade-in: always visible (no JS scroll observer in Divi) */\n.fade-in,.scroll-fade-in{opacity:1 !important;transform:none !important}\n/* === DIVI MOBILE ROW PADDING OVERRIDE === */\n/* Divi injects: @media(max-width:640px){.et_pb_section .et_pb_row{padding:0 24px !important}}\n   Specificity 0,2,0. We use .et_pb_row.et_pb_row (0,2,0 doubled = 0,2,0 still, but\n   .et_pb_section prefix pushes us to 0,3,0) to beat it. */\n@media(max-width:640px){\n  .et_pb_section .et_pb_row.et_pb_row{padding:0 !important}\n}\n/* === MOBILE TOUCH TARGET RESET (WCAG 2.5.8 — 44px minimum) === */\n@media(max-width:768px){\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]),\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]),\n  select,textarea{min-height:44px}\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]){display:inline-flex;align-items:center}\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]){min-height:44px}\n}\n\n@keyframes fadeIn{from{opacity:0}to{opacity:1}}\n@keyframes slide-up{from{opacity:0;transform:translateY(30px)}to{opacity:1;transform:translateY(0)}}\n@keyframes grain{0%,100%{transform:translate(0,0)}10%{transform:translate(-2%,-2%)}20%{transform:translate(2%,2%)}30%{transform:translate(-1%,1%)}40%{transform:translate(1%,-1%)}50%{transform:translate(-2%,2%)}60%{transform:translate(2%,-2%)}70%{transform:translate(-1%,-1%)}80%{transform:translate(1%,1%)}90%{transform:translate(-2%,2%)}}\n@keyframes dw-wave-drift{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n@keyframes dw-scroll{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n/* === HERO (S1) === */\n/* TODO: Review and remap class selectors to use hero prefix */\n/* TODO: Add section container: .hero-section{...;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px} */\n.aiot-hero {\n            background: linear-gradient(135deg, #000432 0%, #000864 50%, #001080 100%);\n            padding: 140px 0 100px;\n            position: relative;\n            overflow: hidden;\n        }\n.aiot-hero::before {\n            content: \'\';\n            position: absolute;\n            top: 0;\n            left: 0;\n            right: 0;\n            bottom: 0;\n            background-image: url("data:image/svg+xml,%3Csvg width=\'60\' height=\'60\' viewBox=\'0 0 60 60\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cg fill=\'none\' fill-rule=\'evenodd\'%3E%3Cg fill=\'%233798E4\' fill-opacity=\'0.08\'%3E%3Cpath d=\'M36 34v-4h-2v4h-4v2h4v4h2v-4h4v-2h-4zm0-30V0h-2v4h-4v2h4v4h2V6h4V4h-4zM6 34v-4H4v4H0v2h4v4h2v-4h4v-2H6zM6 4V0H4v4H0v2h4v4h2V6h4V4H6z\'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E");\n            opacity: 0.5;\n        }\n.aiot-hero-inner {\n            max-width: 1200px;\n            margin: 0 auto;\n            padding: 0 24px;\n            position: relative;\n            z-index: 1;\n        }\n.aiot-hero-grid {\n            display: grid;\n            grid-template-columns: 1fr 1fr;\n            gap: 60px;\n            align-items: center;\n        }\n.aiot-hero-content {\n            text-align: left;\n        }\n.aiot-hero-visual {\n            display: flex;\n            justify-content: center;\n        }\n.aiot-sensor-dashboard {\n            background: rgba(255,255,255,0.08);\n            border: 1px solid rgba(255,255,255,0.15);\n            border-radius: 16px;\n            padding: 24px;\n            width: 100%;\n            max-width: 480px;\n            backdrop-filter: blur(8px);\n        }\n.aiot-dashboard-header {\n            display: flex;\n            align-items: center;\n            justify-content: space-between;\n            margin-bottom: 20px;\n            padding-bottom: 12px;\n            border-bottom: 1px solid rgba(255,255,255,0.1);\n        }\n.aiot-dashboard-title {\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 11px;\n            color: #7EC8F2;\n            text-transform: uppercase;\n            letter-spacing: 0.1em;\n        }\n.aiot-live-badge {\n            display: flex;\n            align-items: center;\n            gap: 6px;\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 10px;\n            color: #22c55e;\n            text-transform: uppercase;\n        }\n.aiot-live-dot {\n            width: 6px;\n            height: 6px;\n            background: #22c55e;\n            border-radius: 50%;\n            animation: pulse-dot 1.5s infinite;\n        }\n.aiot-sensor-grid {\n            display: grid;\n            grid-template-columns: repeat(2, 1fr);\n            gap: 12px;\n            margin-bottom: 20px;\n        }\n.aiot-sensor-tile {\n            background: rgba(0, 175, 240, 0.15);\n            border: 1px solid rgba(0, 175, 240, 0.25);\n            border-radius: 10px;\n            padding: 16px;\n            text-align: center;\n        }\n.aiot-sensor-tile.warning {\n            background: rgba(251, 191, 36, 0.15);\n            border-color: rgba(251, 191, 36, 0.3);\n        }\n.aiot-sensor-tile.alert {\n            background: rgba(239, 68, 68, 0.15);\n            border-color: rgba(239, 68, 68, 0.3);\n        }\n.aiot-sensor-icon {\n            width: 28px;\n            height: 28px;\n            margin: 0 auto 8px;\n        }\n.aiot-sensor-icon svg {\n            width: 100%;\n            height: 100%;\n            stroke: #7EC8F2;\n            stroke-width: 1.5;\n            fill: none;\n        }\n.aiot-sensor-tile.warning .aiot-sensor-icon svg {\n            stroke: #fbbf24;\n        }\n.aiot-sensor-tile.alert .aiot-sensor-icon svg {\n            stroke: #ef4444;\n        }\n.aiot-sensor-value {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 22px;\n            font-weight: 600;\n            color: #fff;\n            margin-bottom: 2px;\n        }\n.aiot-sensor-label {\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 9px;\n            color: rgba(255,255,255,0.75);\n            text-transform: uppercase;\n            letter-spacing: 0.05em;\n        }\n.aiot-machine-list {\n            display: flex;\n            flex-direction: column;\n            gap: 8px;\n        }\n.aiot-machine-row {\n            display: flex;\n            align-items: center;\n            justify-content: space-between;\n            background: rgba(255,255,255,0.05);\n            border-radius: 8px;\n            padding: 10px 14px;\n        }\n.aiot-machine-name {\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 11px;\n            color: rgba(255,255,255,0.8);\n        }\n.aiot-machine-status {\n            display: flex;\n            align-items: center;\n            gap: 6px;\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 10px;\n        }\n.aiot-m