4;\n            line-height: 1.8;\n            margin: 0;\n        }\n.integration-message strong {\n            color: #0369a1;\n        }\n.integration-links {\n            display: flex;\n            gap: 16px;\n            justify-content: center;\n            flex-wrap: wrap;\n            margin-top: 40px;\n        }\n.integration-link {\n            display: inline-flex;\n            align-items: center;\n            gap: 8px;\n            padding: 14px 28px;\n            background: #fff;\n            border: 1px solid #e8eef3;\n            border-radius: 12px;\n            color: #0369a1;\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 14px;\n            font-weight: 600;\n            text-decoration: none;\n            transition: all 0.3s ease;\n        }\n.integration-link:hover {\n            border-color: #00AFF0;\n            background: rgba(0, 175, 240, 0.05);\n            transform: translateY(-2px);\n        }\n.integration-link svg {\n            width: 16px;\n            height: 16px;\n            stroke: currentColor;\n            stroke-width: 2;\n            fill: none;\n        }\n.integration-arrow {\n            color: #0369a1;\n            font-size: 24px;\n            font-weight: 700;\n        }\n@media (max-width: 640px) {\n            .integration-diagram { flex-direction: column; }\n            .integration-arrow { transform: rotate(90deg); }\n        }\n/* Rainbow gradient bar above message */\n.integration-gradient-bar{height:4px;border-radius:4px 4px 0 0;background:linear-gradient(90deg,#00AFF0,#003CC8,#644CE6,#FF6E82,#FFD700,#02D28C);margin:-1px 0 0}\n/* Divi overrides */\n.et_pb_section .integration-header h2{font-weight:700 !important;line-height:1.3 !important;font-size:36px !important}\n.et_pb_section .integration-header p{font-weight:400 !important;padding-bottom:0 !important}\n.et_pb_section .integration-message p{font-weight:400 !important;padding-bottom:0 !important;line-height:1.8 !important}\n.et_pb_section .node-title{font-weight:600 !important}\n/* Defensive SVG sizing */\nsvg:not([width]):not([class]){max-width:48px;max-height:48px}\n@media(prefers-reduced-motion:reduce){}\n/* === SECTION 2 === */\n.et_pb_section:has(.aiot-faq){padding:60px 0 !important;background:#f8fafc !important}\n.aiot-faq{-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.aiot-faq p{padding-bottom:0;line-height:1.6}\n.et_pb_section .aiot-faq h2{margin:0;padding:0;line-height:1.6}\n.aiot-faq summary{-webkit-font-smoothing:auto}\n@media(prefers-reduced-motion:reduce){}\n/* === CTA: START LISTENING TO YOUR MACHINES === */\n.aiot-cta-section{background:linear-gradient(135deg, #00AFF0 0%, #003CC8 100%);padding:100px 24px;position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.aiot-cta-section::before{content:\'\';position:absolute;top:0;left:0;right:0;bottom:0;background-image:url("data:image/svg+xml,%3Csvg width=\'20\' height=\'20\' viewBox=\'0 0 20 20\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cpath d=\'M10 0v20M0 10h20\' stroke=\'%23fff\' stroke-width=\'0.5\' opacity=\'0.05\'/%3E%3C/svg%3E");pointer-events:none;z-index:1}\n.aiot-cta-section::after{content:\'\';position:absolute;bottom:-20%;right:-10%;width:80%;height:80%;background:radial-gradient(ellipse at center,rgba(255,255,255,0.1) 0%,transparent 70%);pointer-events:none;z-index:1}\n.aiot-cta-super-d{position:absolute;top:auto;right:-10%;bottom:-20%;left:auto;width:60%;min-height:60vh;background:url("data:image/svg+xml;base64,") no-repeat center bottom;background-size:contain;opacity:0.14;pointer-events:none;z-index:0;animation:superDGlow 3s ease-in-out infinite}\n@keyframes superDGlow{0%,100%{filter:drop-shadow(0 0 20px rgba(0,175,240,0.1))}50%{filter:drop-shadow(0 0 40px rgba(0,175,240,0.25))}}\n.aiot-cta-wave-flow{position:absolute;bottom:0;left:0;right:0;height:190px;background:linear-gradient(180deg,transparent,rgba(0,60,200,0.15));opacity:0.36;z-index:1;pointer-events:none}\n.aiot-cta-container{position:relative;z-index:3;max-width:700px;margin:0 auto;text-align:center}\n.aiot-cta-title{font-family:\'Noto Sans\',sans-serif;font-weight:700;font-size:40px;color:#fff;line-height:1.6;margin:0 0 16px}\n.aiot-cta-subtitle{font-family:\'Noto Sans\',sans-serif;font-size:20px;color:rgba(255,255,255,0.9);margin:0 0 40px}\n/* Divi overrides — ensure font properties survive Divi cascade */\n.et_pb_section .aiot-cta-title{font-weight:700 !important;font-size:40px !important;line-height:1.6 !important;color:#fff !important}\n.et_pb_section .aiot-cta-subtitle{font-weight:400 !important;padding-bottom:0 !important}\n.et_pb_section .aiot-cta-container p{padding-bottom:0 !important}\n\n.aiot-cta-btn{font-family:\'Noto Sans\',sans-serif;font-size:16px;font-weight:600;padding:16px 32px;border-radius:8px;cursor:pointer;transition:all 0.3s ease;text-decoration:none;display:inline-flex;align-items:center;gap:8px;position:relative;overflow:hidden;border:none;line-height:1.6}\n.aiot-cta-btn::before{content:\'\';position:absolute;top:0;left:-100%;width:100%;height:100%;background:linear-gradient(90deg,transparent,rgba(255,255,255,0.2),transparent);transition:left 0.5s}\n.aiot-cta-btn:hover::before{left:100%}\n.aiot-cta-btn--primary{background:#fff;color:#003CC8;font-weight:600;box-shadow:0 4px 20px rgba(0,0,0,0.15)}\n.aiot-cta-btn--primary:hover{transform:translateY(-3px);box-shadow:0 12px 40px rgba(0,0,0,0.2)}\n.aiot-cta-btn--ghost{background:transparent;color:#fff;border:2px solid rgba(255,255,255,0.6)}\n.aiot-cta-btn--ghost:hover{background:rgba(255,255,255,0.15);border-color:#fff}\n.aiot-cta-btn-row{display:flex;gap:20px;flex-wrap:wrap;justify-content:center;position:relative;z-index:2}\n.aiot-cta-btn{position:static;overflow:visible;display:inline-flex;align-items:center;gap:8px;padding:16px 32px;border-radius:8px;line-height:1.6}\n@media(max-width:767px){\n  .aiot-cta-title{font-size:28px;margin-bottom:16px}\n  .aiot-cta-subtitle{font-size:16px;margin-bottom:32px}\n  .aiot-cta-btn-row{flex-direction:column;align-items:stretch;gap:16px}\n  .aiot-cta-btn{width:100%;max-width:300px;margin:0 auto;text-align:center}\n}\n@media(prefers-reduced-motion:reduce){.aiot-cta-btn{transition:none !important}.aiot-cta-btn::before{display:none}}\n\n.et_pb_section:has(.aiot-related-section){background:#F5F7FA;padding:0}\n.aiot-related-section{padding:60px 5%;background:#F5F7FA;max-width:100%;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto}\n.aiot-related-heading{font-family:\'Noto Sans\',sans-serif;font-size:28px;font-weight:600;color:#000864;margin:0 0 32px 0;padding:0;text-align:center;line-height:1.6;-webkit-font-smoothing:auto}\n.aiot-related-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(280px,1fr));gap:24px;max-width:1200px;margin:0 auto}\n.aiot-related-card{display:block;padding:24px;background:#fff;border-radius:12px;text-decoration:none;border:1px solid #e5e7eb;transition:box-shadow 0.3s ease;color:#333;line-height:1.6}\n.aiot-related-card:hover{box-shadow:0 8px 24px rgba(0,8,100,0.1)}\n.aiot-related-card-title{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:600;color:#000864;margin:0 0 8px 0;padding:0;line-height:1.6;-webkit-font-smoothing:auto}\n.aiot-related-card-desc{font-family:\'Noto Sans\',sans-serif;font-size:14px;color:#666;margin:0;padding:0;line-height:1.5;-webkit-font-smoothing:auto}\n@media(prefers-reduced-motion:reduce){.aiot-related-card{transition:none}}\n\n/* === TB BODY WRAPPER RESET (must be last — beats :has() rules and Divi mobile padding) === */\n/* .et-l--body doesn\'t exist on all WP/Divi versions — use [class*="tb_body"] directly */\n.et_pb_section[class*="tb_body"].et_section_regular{background:transparent !important;background-image:none !important;padding:0 !important;margin:0 !important}\n.et_pb_row[class*="tb_body"].et_pb_row{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important}\n.et_pb_c